using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;
using ResearchAgent.Tools;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrEmpty(apiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.Error.WriteLine("Error: No topic provided.");
    return 1;
}

var notebook = new Notebook();
var searchTool = new WebSearchTool();

IChatClient innerClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsChatClient();

IChatClient agent = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(searchTool.SearchWebAsync),
    AIFunctionFactory.Create(searchTool.ReadWebPageAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetAllNotes),
};

var chatOptions = new ChatOptions { Tools = tools };

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your task is to research a topic thoroughly by
        searching the web, taking notes on key findings, and producing a comprehensive summary.

        Follow this process:
        1. Search for the topic using different relevant queries (at least 2-3 searches).
        2. Optionally read specific web pages to get more detail.
        3. Take notes on the key findings from each search using the note-taking tool.
        4. After gathering enough information, review your notes with GetAllNotes.
        5. Produce a well-organized final summary with sections and key takeaways.

        Be thorough and cover different aspects of the topic.
        Always take notes before producing the final summary.
        """),
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var response = await agent.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n═══════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine();

return 0;

