using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

public sealed class Notebook
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note. Use this to record key findings from your research.")]
    public string AddNote(
        [Description("A short title for the note")] string title,
        [Description("The detailed content of the note")] string content)
    {
        var note = new Note(title, content, DateTime.UtcNow);
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes. Call this before writing your final summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.WriteLine($"  📒 Reviewing {_notes.Count} note(s)");

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===\n");

        for (var i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            sb.AppendLine($"--- Note #{i + 1}: {note.Title} ---");
            sb.AppendLine(note.Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private sealed record Note(string Title, string Content, DateTime SavedAt);
}

