using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient = CreateHttpClient();

    [Description("Search the web for information. Returns a list of results with titles, URLs, and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔎 Searching: \"{query}\"");

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await _httpClient.GetStringAsync(url);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
                return "No search results found.";

            Console.WriteLine($"  ✅ Found {results.Count} results");

            return string.Join("\n\n", results.Select((r, i) =>
                $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Snippet}"));
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ❌ Search failed: {ex.Message}");
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Read the text content of a web page given its URL. Useful for getting more detail from a search result.")]
    public async Task<string> ReadWebPageAsync(
        [Description("The URL of the web page to read")] string url)
    {
        Console.WriteLine($"  📄 Reading: {url}");

        try
        {
            var html = await _httpClient.GetStringAsync(url);
            var text = StripHtml(html);

            // Collapse whitespace and truncate to a reasonable size for the LLM context
            text = CollapseWhitespace().Replace(text, " ").Trim();
            const int maxLength = 8000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[Content truncated]";

            Console.WriteLine($"  ✅ Read {text.Length} characters");
            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract text content from the page."
                : text;
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ❌ Failed to read page: {ex.Message}");
            return $"Failed to read page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();

        foreach (Match match in ResultPattern().Matches(html))
        {
            var rawUrl = WebUtility.HtmlDecode(match.Groups["url"].Value);
            // DuckDuckGo wraps URLs in a redirect; extract the actual target
            var actualUrl = ExtractRedirectUrl(rawUrl);
            var title = StripHtml(WebUtility.HtmlDecode(match.Groups["title"].Value)).Trim();
            var snippet = StripHtml(WebUtility.HtmlDecode(match.Groups["snippet"].Value)).Trim();

            if (!string.IsNullOrEmpty(title) && !string.IsNullOrEmpty(actualUrl))
                results.Add(new SearchResult(title, actualUrl, snippet));

            if (results.Count >= 8)
                break;
        }

        return results;
    }

    private static string ExtractRedirectUrl(string url)
    {
        // DuckDuckGo redirect URLs contain uddg= parameter with the actual URL
        if (url.Contains("uddg="))
        {
            var match = UddgPattern().Match(url);
            if (match.Success)
                return Uri.UnescapeDataString(match.Groups[1].Value);
        }

        return url;
    }

    private static string StripHtml(string html)
    {
        // Remove script and style blocks
        html = ScriptStylePattern().Replace(html, " ");
        // Remove HTML tags
        html = TagPattern().Replace(html, " ");
        // Decode entities
        html = WebUtility.HtmlDecode(html);
        return html;
    }

    private static HttpClient CreateHttpClient()
    {
        var handler = new HttpClientHandler
        {
            AllowAutoRedirect = true,
            AutomaticDecompression = DecompressionMethods.All,
        };
        var client = new HttpClient(handler) { Timeout = TimeSpan.FromSeconds(15) };
        client.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
        client.DefaultRequestHeaders.AcceptLanguage.ParseAdd("en-US,en;q=0.9");
        return client;
    }

    // DuckDuckGo HTML search results: each result has a link and a snippet
    [GeneratedRegex(
        @"<a[^>]+class=""result__a""[^>]+href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ResultPattern();

    [GeneratedRegex(@"uddg=([^&]+)")]
    private static partial Regex UddgPattern();

    [GeneratedRegex(@"<(script|style)[^>]*>.*?</\1>", RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStylePattern();

    [GeneratedRegex(@"<[^>]+>")]
    private static partial Regex TagPattern();

    [GeneratedRegex(@"\s+")]
    private static partial Regex CollapseWhitespace();

    private sealed record SearchResult(string Title, string Url, string Snippet);
}

